import{_ as e,c as a,o,a1 as r}from"./chunks/framework.DILC4Csi.js";const b=JSON.parse('{"title":"Token 统计: 成本监控与数据分析 | Antigravity Manager","description":"学习 Token Stats 统计功能的使用方法。了解如何从响应提取 token 数据、按模型和账号分析用量，通过 Top 列表定位最贵的模型与账号，排查统计缺失问题。","frontmatter":{"title":"Token 统计: 成本监控与数据分析 | Antigravity Manager","sidebarTitle":"一眼看穿谁最贵","subtitle":"Token 统计: 成本监控与数据分析","description":"学习 Token Stats 统计功能的使用方法。了解如何从响应提取 token 数据、按模型和账号分析用量，通过 Top 列表定位最贵的模型与账号，排查统计缺失问题。","tags":["Token Stats","成本","监控","SQLite","用量统计"],"prerequisite":["start-proxy-and-first-client","advanced-model-router"],"order":7},"headers":[],"relativePath":"zh/lbjlaq/Antigravity-Manager/advanced/token-stats/index.md","filePath":"zh/lbjlaq/Antigravity-Manager/advanced/token-stats/index.md"}'),d={name:"zh/lbjlaq/Antigravity-Manager/advanced/token-stats/index.md"};function l(s,t,n,i,c,u){return o(),a("div",null,[...t[0]||(t[0]=[r('<h1 id="token-stats-成本视角的统计口径与图表解读" tabindex="-1">Token Stats：成本视角的统计口径与图表解读 <a class="header-anchor" href="#token-stats-成本视角的统计口径与图表解读" aria-label="Permalink to &quot;Token Stats：成本视角的统计口径与图表解读&quot;">​</a></h1><p>你已经把客户端接进 Antigravity Tools 了，但“到底是谁在烧钱、贵在哪、是不是某个模型突然飙了”通常很难靠直觉判断。这一课只做一件事：把 Token Stats 页里的数据口径讲清楚，并教你用图表快速定位成本问题。</p><h2 id="学完你能做什么" tabindex="-1">学完你能做什么 <a class="header-anchor" href="#学完你能做什么" aria-label="Permalink to &quot;学完你能做什么&quot;">​</a></h2><ul><li>说清楚 Token Stats 的数据来自哪里（什么时候会记录、什么情况下会缺失）</li><li>按小时/日/周切换观察窗口，避免“只看一天”导致误判</li><li>在“按模型/按账号”两种视图下，用趋势图找异常峰值</li><li>用 Top 列表锁定最贵模型/账号，再回到请求日志追根因</li></ul><h2 id="你现在的困境" tabindex="-1">你现在的困境 <a class="header-anchor" href="#你现在的困境" aria-label="Permalink to &quot;你现在的困境&quot;">​</a></h2><ul><li>你感觉调用变贵了，但不知道是模型变了、账号变了，还是某天突然量大</li><li>你看到了 <code>X-Mapped-Model</code>，但不确定统计到底按哪个模型口径算</li><li>Token Stats 里偶尔是 0 或“暂无数据”，不知道是没流量还是没统计到</li></ul><h2 id="什么时候用这一招" tabindex="-1">什么时候用这一招 <a class="header-anchor" href="#什么时候用这一招" aria-label="Permalink to &quot;什么时候用这一招&quot;">​</a></h2><ul><li>你要做成本优化：先把“谁最贵”量化出来</li><li>你在排查突发限流/异常：用峰值时间点去对照请求日志</li><li>你在做模型路由/配额治理配置改动后，想验证成本是否按预期下降</li></ul><h2 id="什么是-token-stats" tabindex="-1">什么是 Token Stats？ <a class="header-anchor" href="#什么是-token-stats" aria-label="Permalink to &quot;什么是 Token Stats？&quot;">​</a></h2><p><strong>Token Stats</strong>是 Antigravity Tools 的本地用量统计页：代理在转发请求后，会尝试从响应 JSON 或流式数据中提取 <code>usage/usageMetadata</code> 里的 token 数，并把每次请求按账号与模型写入本机 SQLite（<code>token_stats.db</code>），最后在 UI 里按时间/模型/账号汇总展示。</p><div class="info custom-block"><p class="custom-block-title">先说明一个容易踩的点</p><p>Token Stats 的“模型”口径来自你请求里的 <code>model</code> 字段（或 Gemini 的 <code>/v1beta/models/&lt;model&gt;</code> 路径解析），不等于路由后的 <code>X-Mapped-Model</code>。</p></div><h2 id="🎒-开始前的准备" tabindex="-1">🎒 开始前的准备 <a class="header-anchor" href="#🎒-开始前的准备" aria-label="Permalink to &quot;🎒 开始前的准备&quot;">​</a></h2><ul><li>你已经跑通过一次代理调用（不会只停留在 <code>/healthz</code> 探活）</li><li>你的上游响应会返回可解析的 token 用量字段（否则统计会缺失）</li></ul><div class="tip custom-block"><p class="custom-block-title">推荐搭配阅读</p><p>如果你正在用模型映射把 <code>model</code> 路由到别的物理模型，建议先看 <strong><a href="/docs/opencodedocs/zh/lbjlaq/Antigravity-Manager/advanced/model-router/">模型路由：自定义映射、通配符优先级与预设策略</a></strong>，再回来看“统计口径”会更直观。</p></div><h2 id="核心思路" tabindex="-1">核心思路 <a class="header-anchor" href="#核心思路" aria-label="Permalink to &quot;核心思路&quot;">​</a></h2><p>Token Stats 的数据链路可以拆成三段：</p><ol><li>代理中间件尝试从响应里提取 token 用量（兼容 <code>usage</code>/<code>usageMetadata</code>，流式也会解析）</li><li>如果同时拿到了 <code>account_email + input_tokens + output_tokens</code>，就写入本机 SQLite（<code>token_stats.db</code>）</li><li>UI 通过 Tauri <code>invoke(get_token_stats_*)</code> 拉取聚合数据，按小时/日/周展示</li></ol><h2 id="跟我做" tabindex="-1">跟我做 <a class="header-anchor" href="#跟我做" aria-label="Permalink to &quot;跟我做&quot;">​</a></h2><h3 id="第-1-步-先确认你-有流量" tabindex="-1">第 1 步：先确认你“有流量” <a class="header-anchor" href="#第-1-步-先确认你-有流量" aria-label="Permalink to &quot;第 1 步：先确认你“有流量”&quot;">​</a></h3><p><strong>为什么</strong> Token Stats 统计来自真实请求。只启动代理但没发过一次模型请求，页面就会显示“暂无数据”。</p><p>做法：复用你在 <strong><a href="/docs/opencodedocs/zh/lbjlaq/Antigravity-Manager/start/proxy-and-first-client/">启动本地反代并接入第一个客户端</a></strong> 里已经验证成功的那种调用方式，发 1-2 次请求。</p><p><strong>你应该看到</strong>：Token Stats 页面从“加载中/暂无数据”变成有图表或列表。</p><h3 id="第-2-步-选对时间窗口-小时-日-周" tabindex="-1">第 2 步：选对时间窗口（小时/日/周） <a class="header-anchor" href="#第-2-步-选对时间窗口-小时-日-周" aria-label="Permalink to &quot;第 2 步：选对时间窗口（小时/日/周）&quot;">​</a></h3><p><strong>为什么</strong> 同一份数据在不同窗口下看到的“峰值/趋势”完全不一样。UI 里三种窗口对应的取数范围也不同：</p><ul><li>小时：最近 24 小时</li><li>日：最近 7 天</li><li>周：最近 4 周（趋势视图会按最近 30 天聚合）</li></ul><p><strong>你应该看到</strong>：切换后，趋势图横轴粒度变化（小时显示到“时”，日显示到“月/日”，周显示到“年-W周号”）。</p><h3 id="第-3-步-先看顶部总览-确定-成本规模" tabindex="-1">第 3 步：先看顶部总览，确定“成本规模” <a class="header-anchor" href="#第-3-步-先看顶部总览-确定-成本规模" aria-label="Permalink to &quot;第 3 步：先看顶部总览，确定“成本规模”&quot;">​</a></h3><p><strong>为什么</strong> 总览卡片能先回答 3 个问题：总量大不大、输入/输出占比是否异常、参与的账号/模型是不是突然变多。</p><p>重点看这几项：</p><ul><li>总 Token（<code>total_tokens</code>）</li><li>输入/输出 Token（<code>total_input_tokens</code> / <code>total_output_tokens</code>）</li><li>活跃账号数（<code>unique_accounts</code>）</li><li>使用模型数（UI 直接用“分模型统计列表”的长度）</li></ul><p><strong>你应该看到</strong>：如果“活跃账号数”突然飙高，通常意味着你在短时间内跑了更多账号（例如切换到轮换策略）。</p><h3 id="第-4-步-用-分模型-分账号使用趋势-抓异常峰值" tabindex="-1">第 4 步：用“分模型/分账号使用趋势”抓异常峰值 <a class="header-anchor" href="#第-4-步-用-分模型-分账号使用趋势-抓异常峰值" aria-label="Permalink to &quot;第 4 步：用“分模型/分账号使用趋势”抓异常峰值&quot;">​</a></h3><p><strong>为什么</strong> 趋势图是最适合抓“突然变贵”的入口。你不用先知道原因，先把“哪天/哪小时飙了”圈出来。</p><p>做法：</p><ol><li>在趋势图右上角切换「按模型 / 按账号」</li><li>鼠标悬停（Tooltip）看 Top 值，优先关注“突然冲到第一的那条”</li></ol><p><strong>你应该看到</strong>：</p><ul><li>按模型：某个模型在某个时间段突然抬升</li><li>按账号：某个账号在某个时间段突然抬升</li></ul><h3 id="第-5-步-用-top-列表把-最贵目标-锁死" tabindex="-1">第 5 步：用 Top 列表把“最贵目标”锁死 <a class="header-anchor" href="#第-5-步-用-top-列表把-最贵目标-锁死" aria-label="Permalink to &quot;第 5 步：用 Top 列表把“最贵目标”锁死&quot;">​</a></h3><p><strong>为什么</strong> 趋势图告诉你“什么时候异常”，Top 列表告诉你“谁最贵”。把这两个交叉，就能快速定位排障范围。</p><p>做法：</p><ul><li>在「按模型」视图下，看“分模型详细统计”表格的 <code>total_tokens / request_count / 占比</code></li><li>在「按账号」视图下，看“账号详细统计”表格的 <code>total_tokens / request_count</code></li></ul><p><strong>你应该看到</strong>：最贵模型/账号排在前面，且 <code>request_count</code> 能帮你区分“单次特别贵”还是“次数特别多”。</p><h3 id="第-6-步-可选-找到-token-stats-db-做备份-核对" tabindex="-1">第 6 步（可选）：找到 <code>token_stats.db</code>，做备份/核对 <a class="header-anchor" href="#第-6-步-可选-找到-token-stats-db-做备份-核对" aria-label="Permalink to &quot;第 6 步（可选）：找到 `token_stats.db`，做备份/核对&quot;">​</a></h3><p><strong>为什么</strong> 当你怀疑“统计缺失”或想做离线分析时，直接拿 SQLite 文件最靠谱。</p><p>做法：进入 Settings 的 Advanced 区域，点击“打开数据目录”，你会在数据目录里找到 <code>token_stats.db</code>。</p><p><strong>你应该看到</strong>：文件列表里有 <code>token_stats.db</code>（文件名由后端写死）。</p><h2 id="检查点-✅" tabindex="-1">检查点 ✅ <a class="header-anchor" href="#检查点-✅" aria-label="Permalink to &quot;检查点 ✅&quot;">​</a></h2><ul><li>你能说清楚 Token Stats 统计是“从响应里的 usage/usageMetadata 提取后落到本地 SQLite”，不是云端计费</li><li>你能在“按模型/按账号”两种趋势视图下，指出一个具体的峰值时间段</li><li>你能用 Top 列表给出一个可执行的排查结论：先查哪个模型或账号</li></ul><h2 id="踩坑提醒" tabindex="-1">踩坑提醒 <a class="header-anchor" href="#踩坑提醒" aria-label="Permalink to &quot;踩坑提醒&quot;">​</a></h2><table tabindex="0"><thead><tr><th>现象</th><th>常见原因</th><th>你可以怎么做</th></tr></thead><tbody><tr><td>Token Stats 显示&quot;暂无数据&quot;</td><td>你确实没产生模型请求；或上游响应没带可解析的 token 字段</td><td>先复用已验证可用的客户端发请求；再看响应里是否包含 <code>usage/usageMetadata</code></td></tr><tr><td>统计按&quot;模型&quot;看起来不对</td><td>统计口径使用请求里的 <code>model</code>，不是 <code>X-Mapped-Model</code></td><td>把模型路由当成&quot;请求模型 -&gt; 映射模型&quot;；统计看的是&quot;请求模型&quot;</td></tr><tr><td>账号维度缺失</td><td>只有拿到 <code>X-Account-Email</code> 且解析到 token 用量时才会写入</td><td>确认请求确实走到了账号池；再对照请求日志/响应头</td></tr><tr><td>启用 Proxy Monitor 后统计数据偏大</td><td>当 Proxy Monitor 启用时，每次请求的 token 会被记录两次</td><td>这已知的实现细节，不影响相对趋势分析；如果需要精确值，可以临时禁用 Monitor 后重测</td></tr></tbody></table><h2 id="本课小结" tabindex="-1">本课小结 <a class="header-anchor" href="#本课小结" aria-label="Permalink to &quot;本课小结&quot;">​</a></h2><ul><li>Token Stats 的核心价值是&quot;把成本问题量化&quot;，先定位，再优化</li><li>统计写入时，账号和 token 用量是必须的；模型缺失时会被记录为 <code>&quot;unknown&quot;</code>（不会阻止写入）</li><li>想做更精细的成本控制，下一步通常会回到模型路由或配额治理</li></ul><h2 id="下一课预告" tabindex="-1">下一课预告 <a class="header-anchor" href="#下一课预告" aria-label="Permalink to &quot;下一课预告&quot;">​</a></h2><blockquote><p>下一课我们解决长会话里的“隐性稳定性问题”：<strong><a href="/docs/opencodedocs/zh/lbjlaq/Antigravity-Manager/advanced/context-compression/">长会话稳定性：上下文压缩、签名缓存与工具结果压缩</a></strong>。</p></blockquote><p>你会学到：</p><ul><li>三层渐进式上下文压缩分别在做什么</li><li>为什么“签名缓存”能减少 400 签名错误</li><li>工具结果压缩会删掉什么、保留什么</li></ul><hr><h2 id="附录-源码参考" tabindex="-1">附录：源码参考 <a class="header-anchor" href="#附录-源码参考" aria-label="Permalink to &quot;附录：源码参考&quot;">​</a></h2><details><summary><strong>点击展开查看源码位置</strong></summary><blockquote><p>更新时间：2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>功能</th><th>文件路径</th><th>行号</th></tr></thead><tbody><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>Token Stats UI：时间窗口/视图切换与取数</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/pages/TokenStats.tsx#L49-L166" target="_blank" rel="noreferrer"><code>src/pages/TokenStats.tsx</code></a></td><td>49-166</td></tr><tr><td>Token Stats UI：空数据提示（&quot;暂无数据&quot;）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/pages/TokenStats.tsx#L458-L507" target="_blank" rel="noreferrer"><code>src/pages/TokenStats.tsx</code></a></td><td>458-507</td></tr><tr><td>Token 用量提取：从请求解析 model、从响应解析 usage/usageMetadata</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/middleware/monitor.rs#L32-L120" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/middleware/monitor.rs</code></a></td><td>32-120</td></tr><tr><td>Token 用量提取：流式与 JSON 响应解析 usage 字段</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/middleware/monitor.rs#L122-L336" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/middleware/monitor.rs</code></a></td><td>122-336</td></tr><tr><td>Token Stats 写入点：拿到账号+token 后写入 SQLite</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/monitor.rs#L79-L136" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/monitor.rs</code></a></td><td>79-136</td></tr><tr><td>数据库文件名与表结构：<code>token_stats.db</code> / <code>token_usage</code> / <code>token_stats_hourly</code></td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/modules/token_stats.rs#L58-L126" target="_blank" rel="noreferrer"><code>src-tauri/src/modules/token_stats.rs</code></a></td><td>58-126</td></tr><tr><td>写入逻辑：<code>record_usage(account_email, model, input, output)</code></td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/modules/token_stats.rs#L128-L159" target="_blank" rel="noreferrer"><code>src-tauri/src/modules/token_stats.rs</code></a></td><td>128-159</td></tr><tr><td>查询逻辑：小时/日/周、按账号/按模型、趋势与总览</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/modules/token_stats.rs#L161-L555" target="_blank" rel="noreferrer"><code>src-tauri/src/modules/token_stats.rs</code></a></td><td>161-555</td></tr><tr><td>Tauri 命令：<code>get_token_stats_*</code> 对前端暴露</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/commands/mod.rs#L791-L847" target="_blank" rel="noreferrer"><code>src-tauri/src/commands/mod.rs</code></a></td><td>791-847</td></tr><tr><td>应用启动时初始化 Token Stats DB</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/lib.rs#L50-L56" target="_blank" rel="noreferrer"><code>src-tauri/src/lib.rs</code></a></td><td>50-56</td></tr><tr><td>设置页：获取/打开数据目录（用于找到 <code>token_stats.db</code>）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/pages/Settings.tsx#L76-L143" target="_blank" rel="noreferrer"><code>src/pages/Settings.tsx</code></a></td><td>76-143</td></tr></tbody></table></details>',59)])])}const g=e(d,[["render",l]]);export{b as __pageData,g as default};
